    return FfiConverterTypeFfiVault.lower(value)
}


/**
 * Item summary exposed to Swift. No secret material — callers use a
 * separate (future) API to request copy/reveal for a specific field.
 */
public struct FfiItemSummary {
    /**
     * Stable item identifier as a hyphenated UUID string. Swift keeps
     * this opaque and passes it back to Rust for further operations.
     */
    public var id: String
    public var title: String
    public var kind: FfiItemKind
    public var username: String?
    public var url: String?
    public var hasPassword: Bool
    public var hasTotp: Bool
    public var createdAtMs: UInt64
    public var modifiedAtMs: UInt64

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Stable item identifier as a hyphenated UUID string. Swift keeps
         * this opaque and passes it back to Rust for further operations.
         */id: String, title: String, kind: FfiItemKind, username: String?, url: String?, hasPassword: Bool, hasTotp: Bool, createdAtMs: UInt64, modifiedAtMs: UInt64) {
        self.id = id
        self.title = title
        self.kind = kind
        self.username = username
        self.url = url
        self.hasPassword = hasPassword
        self.hasTotp = hasTotp
        self.createdAtMs = createdAtMs
        self.modifiedAtMs = modifiedAtMs
    }
}



extension FfiItemSummary: Equatable, Hashable {
    public static func ==(lhs: FfiItemSummary, rhs: FfiItemSummary) -> Bool {
        if lhs.id != rhs.id {
            return false
        }
        if lhs.title != rhs.title {
            return false
        }
        if lhs.kind != rhs.kind {
            return false
        }
        if lhs.username != rhs.username {
            return false
        }
        if lhs.url != rhs.url {
            return false
        }
        if lhs.hasPassword != rhs.hasPassword {
            return false
        }
        if lhs.hasTotp != rhs.hasTotp {
            return false
        }
        if lhs.createdAtMs != rhs.createdAtMs {
            return false
        }
        if lhs.modifiedAtMs != rhs.modifiedAtMs {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(id)
        hasher.combine(title)
        hasher.combine(kind)
        hasher.combine(username)
        hasher.combine(url)
        hasher.combine(hasPassword)
        hasher.combine(hasTotp)
        hasher.combine(createdAtMs)
        hasher.combine(modifiedAtMs)
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiItemSummary: FfiConverterRustBuffer {
    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiItemSummary {
        return
            try FfiItemSummary(
                id: FfiConverterString.read(from: &buf), 
                title: FfiConverterString.read(from: &buf), 
                kind: FfiConverterTypeFfiItemKind.read(from: &buf), 
                username: FfiConverterOptionString.read(from: &buf), 
                url: FfiConverterOptionString.read(from: &buf), 
