/**
 * Flat error enum exposed to Swift. The 5-category `VaultError` taxonomy
 * collapses to this shape because UniFFI renders nested enums less
 * ergonomically in Swift than a flat category-tagged enum.
 *
 * Swift code should pattern-match on the variant and show the
 * category-appropriate headline from its own copy tables — the `message`
 * field is log text, not UI copy.
 */
public enum FfiError {

    
    
    /**
     * Something the user can fix by retrying with different input.
     */
    case UserActionable(message: String
    )
    /**
     * Temporary environmental failure. Retry later.
     */
    case NetworkTransient(message: String
    )
    /**
     * Device hardware state prevents the operation.
     */
    case HardwareIssue(message: String
    )
    /**
     * A bug inside unovault. The user should see "copy diagnostics".
     */
    case BugInUnovault(message: String
    )
    /**
     * The OS sandbox or permission system refused the operation.
     */
    case PlatformPolicy(message: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiError: FfiConverterRustBuffer {
    typealias SwiftType = FfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .UserActionable(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .NetworkTransient(
            message: try FfiConverterString.read(from: &buf)
            )
        case 3: return .HardwareIssue(
            message: try FfiConverterString.read(from: &buf)
            )
        case 4: return .BugInUnovault(
            message: try FfiConverterString.read(from: &buf)
            )
        case 5: return .PlatformPolicy(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .UserActionable(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .NetworkTransient(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .HardwareIssue(message):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .BugInUnovault(message):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .PlatformPolicy(message):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


extension FfiError: Equatable, Hashable {}

extension FfiError: Foundation.LocalizedError {
    public var errorDescription: String? {
        String(reflecting: self)
    }
}

// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * Kind of a vault item. Mirrors `unovault_core::event::ItemKind` but as
 * a UniFFI-compatible enum (no `#[non_exhaustive]`; UniFFI needs full
 * enumeration at binding time).
 */

public enum FfiItemKind {
    
    case password
    case passkey
    case totp
    case sshKey
    case apiToken
    case secureNote
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiItemKind: FfiConverterRustBuffer {
    typealias SwiftType = FfiItemKind

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiItemKind {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .password
        
        case 2: return .passkey
        
        case 3: return .totp
        
        case 4: return .sshKey
        
        case 5: return .apiToken
        
        case 6: return .secureNote
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiItemKind, into buf: inout [UInt8]) {
        switch value {
        
        
        case .password:
            writeInt(&buf, Int32(1))
        
        
        case .passkey:
            writeInt(&buf, Int32(2))
        
        
        case .totp:
            writeInt(&buf, Int32(3))
        
        
        case .sshKey:
            writeInt(&buf, Int32(4))
        
        
        case .apiToken:
            writeInt(&buf, Int32(5))
        
        
        case .secureNote:
            writeInt(&buf, Int32(6))
        
        }
    }
}


