private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private var initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 26
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_unovault_ffi_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_unovault_ffi_checksum_func_ffi_version() != 47163) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_func_format_version() != 9553) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_add_item() != 53813) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_bundle_path() != 5919) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_install_id() != 33483) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_item_count() != 61163) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_list_items() != 15510) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_save() != 32145) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_set_notes() != 60300) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_method_ffivault_set_password() != 32027) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_constructor_ffivault_create() != 25223) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_unovault_ffi_checksum_constructor_ffivault_unlock() != 65029) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

private func uniffiEnsureInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

